CREATE OR REPLACE VIEW vmb_loan_clear (loan_type, membership_no, loan_contract_no, principal_balance, interest, period_payment_amount, clear_status) AS select sc_lon_m_rule_clearloan.loan_type , tb.membership_no ,tb.loan_contract_no , tb.principal_balance , tb.interest
  , CASE WHEN  sc_lon_m_rule.drop_all ='1' THEN  0   ELSE tb.period_payment_amount END  as period_payment_amount 
       
      ,( select count( 1 ) 
        FROM sc_lon_m_rule_clearloan 
        where 1=1
        and sc_lon_m_rule_clearloan.loan_type = sc_lon_m_rule.loan_type
        and sc_lon_m_rule_clearloan.old_loan_type = tb.loan_type )  as  clear_status

from (
      select sc_lon_m_loan_card.loan_type
      ,sc_lon_m_loan_card.membership_no 
	,sc_lon_m_loan_card.loan_contract_no 
     --Niorn 2023-05-04 TGE  Credit pending 
     , CASE WHEN  pka.isCoop('TGE')     ='1' THEN  sc_lon_m_loan_card.principal_balance - pending_amount      ELSE sc_lon_m_loan_card.principal_balance END   as principal_balance 
     
    , pka_mobile_lon.fp_cal_int( sc_lon_m_loan_card.loan_contract_no,to_date(statement_timestamp() ,'dd/mm/yyyy')) as interest


   ,sc_lon_m_contract.period_payment_amount

from sc_lon_m_loan_card  
,sc_lon_m_contract
      where 1=1    
and sc_lon_m_contract.loan_contract_no =  sc_lon_m_loan_card.loan_contract_no     
      and sc_lon_m_loan_card.principal_balance > 0
) tb
,sc_lon_m_rule
,sc_lon_m_rule_clearloan 
where 1=1
and sc_lon_m_rule.loan_type = tb.loan_type
and sc_lon_m_rule_clearloan.old_loan_type = tb.loan_type
-- and sc_lon_m_rule_clearloan.loan_type = '20'
-- and tb.membership_no = '059310';310'
;

